/** Convertit lat/lng → coordonnées SVG (espace 2560×1440) via transformation affine calibrée */
export function geoToSVG(lat: number, lng: number): { x: number; y: number } {
  return {
    x: 1235.6425215450581 * lng + 6.1638625133782625 * lat - 5172.627925723791,
    y: 18.035939851368312 * lng - 1627.8735592938028 * lat + 71486.5967656225,
  };
}
